// =============================================================================
// 🧠 3. DATABASE EXPANSION & ENGINE
// =============================================================================

const BARCODE_INDEX: Record<string, string> = {};

/**
 * Deterministic EAN-13 Checksum Generator
 */
const generateEAN13 = (countryCode: number, companyCode: string, itemIndex: number): string => {
  const base = `${countryCode.toString().padStart(3, '0')}${companyCode.padStart(5, '0')}${itemIndex.toString().padStart(4, '0')}`;
  let oddSum = 0, evenSum = 0;
  for (let i = 0; i < 12; i++) {
    const digit = parseInt(base[i]);
    if (i % 2 === 0) oddSum += digit;
    else evenSum += digit;
  }
  const checkDigit = (10 - ((oddSum * 3 + evenSum) % 10)) % 10;
  return `${base}${checkDigit}`;
};

const EXPAND_DATABASE = (templates: Omit<DrinkRecord, 'id' | 'barcode' | 'region'>[]): Record<string, DrinkRecord> => {
  const db: Record<string, DrinkRecord> = {};
  templates.forEach((t, i) => {
    // Generate regional variants (Phase 1 & 2)
    const regions = ['US', 'KE', 'UK', 'EU', 'JP', 'BR', 'CA', 'AU', 'ZA', 'IN'];
    regions.forEach((reg, ri) => {
      const id = `drk_${i}_${reg.toLowerCase()}`;

      const countryCodeMap: Record<string, number> = { US: 0, UK: 5, EU: 4, CA: 6, AU: 9, ZA: 6, KE: 6, JP: 4, IN: 8, BR: 7 };
      const cc = countryCodeMap[reg] || 1;
      const bc = generateEAN13(cc, t.brand.slice(0, 4).toUpperCase().padEnd(5, 'X'), i % 10000);

      // Deterministic adjustments for regional variants
      const isZeroVar = t.name.toLowerCase().includes('zero') || t.name.toLowerCase().includes('diet');
      const finalImpact = Math.min(100, Math.max(0, isZeroVar ? t.impactScore + 15 : t.impactScore));

      const record: DrinkRecord = {
        ...t,
        id,
        name: t.name + (ri === 0 ? '' : ` (${reg})`),
        barcode: [bc],
        region: [reg],
        keywords: [...t.keywords, reg.toLowerCase(), bc],
        impactScore: finalImpact,
        hydrationIndex: Math.min(100, t.hydrationIndex + (isZeroVar ? 5 : 0)),
      };
      db[id] = record;
      db[bc] = record;
      BARCODE_INDEX[bc] = id;
    });
  });
  return db;
};

const BEVERAGE_DB = EXPAND_DATABASE(BASE_TEMPLATES);

const fuse = new Fuse(Object.values(BEVERAGE_DB), {
  keys: ['name', 'brand', 'keywords'],
  threshold: 0.35,
  includeScore: true,
});

// Safe storage access
const storage = (function() {
  try {
    // @ts-ignore
    return new MMKV({ id: 'liquid_impact_cache' });
  } catch (e) {
    return { getString: () => null, set: () => {}, delete: () => {} } as any;
  }
})();

const CacheManager = {
  get: (key: string) => {
    const raw = storage.getString(key);
    if (!raw) return null;
    try {
      const { data, expires } = JSON.parse(raw);
      if (Date.now() > expires) { try { (storage as any).delete(key); } catch {} return null; }
      return data;
    } catch { return null; }
  },
  set: (key: string, data: any, ttl: number) => {
    try { storage.set(key, JSON.stringify({ data, expires: Date.now() + ttl })); } catch {}
  }
};

const processImageForOCR = async (uri: string): Promise<string> => {
  try {
    if (TextRecognition) {
      const result = await TextRecognition.recognize(uri);
      return result.text || "";
    }
    await new Promise(resolve => setTimeout(resolve, 800));
    return "";
  } catch (e) { return ""; }
};

